using System;
using System.Reflection;
using System.Linq;

class Program
{
    static void Main()
    {
        Console.WriteLine("=== MICROSOFT.AGENTS.AI TYPES ===\n");
        var agentsAsm = Assembly.Load("Microsoft.Agents.AI");
        PrintPublicTypes(agentsAsm, "Microsoft.Agents.AI");

        Console.WriteLine("\n\n=== MICROSOFT.EXTENSIONS.AI TYPES ===\n");
        var extAsm = Assembly.Load("Microsoft.Extensions.AI");
        PrintPublicTypes(extAsm, "Microsoft.Extensions.AI");
    }

    static void PrintPublicTypes(Assembly asm, string name)
    {
        var types = asm.GetTypes()
            .Where(t => t.IsPublic && !t.Name.StartsWith("<"))
            .OrderBy(t => t.Namespace)
            .ThenBy(t => t.Name)
            .ToList();

        var byNamespace = types.GroupBy(t => t.Namespace).OrderBy(g => g.Key);

        foreach(var ns in byNamespace)
        {
            Console.WriteLine($"Namespace: {ns.Key}");
            foreach(var t in ns)
            {
                var suffix = t.IsInterface ? " (interface)" : 
                             t.IsAbstract ? " (abstract)" : "";
                Console.WriteLine($"  - {t.Name}{suffix}");
            }
            Console.WriteLine();
        }

        Console.WriteLine($"Total public types: {types.Count}");
    }
}
