using System;
using System.Reflection;
using System.Linq;

class Program
{
    static void Main()
    {
        var extAsm = Assembly.Load("Microsoft.Extensions.AI");
        var agentsAsm = Assembly.Load("Microsoft.Agents.AI");

        Console.WriteLine("=== ChatOptions (Microsoft.Extensions.AI) ===");
        PrintTypeDetails(extAsm.GetType("Microsoft.Extensions.AI.ChatOptions"));

        Console.WriteLine("\n\n=== AITool (Microsoft.Extensions.AI) ===");
        PrintTypeDetails(extAsm.GetType("Microsoft.Extensions.AI.AITool"));

        Console.WriteLine("\n\n=== AIFunction (Microsoft.Extensions.AI) ===");
        PrintTypeDetails(extAsm.GetType("Microsoft.Extensions.AI.AIFunction"));

        Console.WriteLine("\n\n=== IChatClient (Microsoft.Extensions.AI) ===");
        PrintTypeDetails(extAsm.GetType("Microsoft.Extensions.AI.IChatClient"));

        Console.WriteLine("\n\n=== ChatClientAgent (Microsoft.Agents.AI) ===");
        PrintTypeDetails(agentsAsm.GetType("Microsoft.Agents.AI.ChatClientAgent"));

        Console.WriteLine("\n\n=== ChatClientAgentOptions (Microsoft.Agents.AI) ===");
        PrintTypeDetails(agentsAsm.GetType("Microsoft.Agents.AI.ChatClientAgentOptions"));

        Console.WriteLine("\n\n=== ChatClientAgentRunOptions (Microsoft.Agents.AI) ===");
        PrintTypeDetails(agentsAsm.GetType("Microsoft.Agents.AI.ChatClientAgentRunOptions"));

        Console.WriteLine("\n\n=== FunctionInvokingChatClient (Microsoft.Extensions.AI) ===");
        PrintTypeDetails(extAsm.GetType("Microsoft.Extensions.AI.FunctionInvokingChatClient"));
    }

    static void PrintTypeDetails(Type t)
    {
        if (t == null)
        {
            Console.WriteLine("Type not found!");
            return;
        }

        Console.WriteLine($"Type: {t.Name}");
        Console.WriteLine($"Base: {t.BaseType?.Name}");
        Console.WriteLine($"Is Interface: {t.IsInterface}");
        Console.WriteLine($"Is Abstract: {t.IsAbstract}");

        var interfaces = t.GetInterfaces();
        if (interfaces.Length > 0)
        {
            Console.WriteLine("\nInterfaces:");
            foreach (var i in interfaces)
            {
                Console.WriteLine($"  - {i.Name}");
            }
        }

        var props = t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static);
        if (props.Length > 0)
        {
            Console.WriteLine("\nPublic Properties:");
            foreach (var p in props.Take(20))
            {
                var getter = p.GetGetMethod() != null ? "get" : "";
                var setter = p.GetSetMethod() != null ? "set" : "";
                Console.WriteLine($"  - {p.PropertyType.Name} {p.Name} {{{getter}{(getter && setter ? "; " : "")}{setter}}}");
            }
            if (props.Length > 20)
                Console.WriteLine($"  ... and {props.Length - 20} more");
        }

        var methods = t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
        if (methods.Length > 0)
        {
            Console.WriteLine("\nPublic Methods (declared in this type):");
            foreach (var m in methods.Take(15))
            {
                var args = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name));
                Console.WriteLine($"  - {m.ReturnType.Name} {m.Name}({args})");
            }
            if (methods.Length > 15)
                Console.WriteLine($"  ... and {methods.Length - 15} more");
        }

        var ctors = t.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
        if (ctors.Length > 0)
        {
            Console.WriteLine("\nPublic Constructors:");
            foreach (var c in ctors.Take(10))
            {
                var args = string.Join(", ", c.GetParameters().Select(p => p.ParameterType.Name));
                Console.WriteLine($"  - {c.DeclaringType?.Name}({args})");
            }
            if (ctors.Length > 10)
                Console.WriteLine($"  ... and {ctors.Length - 10} more");
        }
    }
}
